#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <fstream>
#include <cstdio>

// This driver assumes the compiled program is named '4175.exe' on Windows or '4175' on Linux/macOS.
// It runs the program with redirected input and captures its output.
std::string run_program_with_input(const std::string& input_str) {
    std::ofstream input_file("temp_input.txt");
    input_file << input_str;
    input_file.close();

    // Execute the program, redirecting stdin and stdout
    #ifdef _WIN32
        system("4175.exe < temp_input.txt > temp_output.txt");
    #else
        system("./4175 < temp_input.txt > temp_output.txt");
    #endif

    std::ifstream output_file("temp_output.txt");
    std::stringstream buffer;
    buffer << output_file.rdbuf();
    output_file.close();

    remove("temp_input.txt");
    remove("temp_output.txt");

    return buffer.str();
}

